/**
 * GuardClaw Stats Dashboard
 *
 * HTTP handler that serves:
 *   - GET  /plugins/guardclaw/stats              → Dashboard HTML (inline SPA)
 *   - GET  /plugins/guardclaw/stats/api/summary  → JSON summary
 *   - GET  /plugins/guardclaw/stats/api/hourly   → JSON hourly timeline
 *   - GET  /plugins/guardclaw/stats/api/sessions → JSON session stats
 *   - GET  /plugins/guardclaw/stats/api/detections → JSON detection event log
 *   - GET  /plugins/guardclaw/stats/api/config   → current guardclaw config
 *   - POST /plugins/guardclaw/stats/api/config   → update config (hot-reload + persist)
 *   - GET  /plugins/guardclaw/stats/api/prompts  → all editable prompts
 *   - POST /plugins/guardclaw/stats/api/prompts  → save a prompt (hot-reload)
 *   - POST /plugins/guardclaw/stats/api/reset          → reset all token stats
 *   - POST /plugins/guardclaw/stats/api/test-classify → dry-run pipeline classification
 *   - GET  /plugins/guardclaw/stats/api/presets        → list all presets (builtin + user)
 *   - POST /plugins/guardclaw/stats/api/presets/apply  → apply a preset (hot-reload)
 *   - POST /plugins/guardclaw/stats/api/presets/save   → save current config as preset
 *   - DELETE /plugins/guardclaw/stats/api/presets/:id  → delete a user preset
 *   - GET  /plugins/guardclaw/stats/api/suggestions          → model advisor suggestions
 *   - POST /plugins/guardclaw/stats/api/suggestions/:id/accept  → accept a suggestion
 *   - POST /plugins/guardclaw/stats/api/suggestions/:id/dismiss → dismiss a suggestion
 *   - POST /plugins/guardclaw/stats/api/advisor/run             → trigger immediate check
 *   - GET  /plugins/guardclaw/stats/api/budget                  → current budget snapshot
 */

import type { IncomingMessage, ServerResponse } from "node:http";
import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import type { RouterPipeline } from "./router-pipeline.js";
import { getLiveConfig, getLiveInjectionConfig, updateLiveConfig, updateLiveInjectionConfig } from "./live-config.js";
import { DEFAULT_DETECTION_SYSTEM_PROMPT, DEFAULT_PII_EXTRACTION_PROMPT } from "./local-model.js";
import {
  addCorrection,
  deleteCorrection,
  getCorrections,
  loadCorrections,
} from "./correction-store.js";
import { getCurrentLoopHighestLevel } from "./loop-detection-level.js";
import {
  listPresets,
  applyPreset as applyPresetAction,
  saveCurrentAsPreset,
  deletePreset as deletePresetAction,
} from "./presets.js";
import { loadPrompt, readPromptFromDisk, writePrompt } from "./prompt-loader.js";
import { createConfigurableRouter } from "./routers/configurable.js";
import { DEFAULT_JUDGE_PROMPT } from "./routers/token-saver.js";
import { getAllSessionStates } from "./session-state.js";
import { getGlobalCollector } from "./token-stats.js";
import {
  getLastReplyLoopSummary,
  getLastReplyModelOrigin,
  getLastTurnTokens,
} from "./usage-intel.js";
import {
  getSuggestions,
  acceptSuggestion,
  dismissSuggestion,
  runAdvisorChecks,
  getLastCheckedAt,
} from "./model-advisor.js";
import { getBudgetSnapshot, getDailyCost, getMonthlyCost } from "./budget-guard.js";

const GUARDCLAW_CONFIG_PATH = join(process.env.HOME ?? "/tmp", ".openclaw", "guardclaw.json");
const GUARDCLAW_INJECTIONS_PATH = join(process.env.HOME ?? "/tmp", ".openclaw", "guardclaw-injections.json");
const GUARDCLAW_STATS_PATH = join(process.env.HOME ?? "/tmp", ".openclaw", "guardclaw-stats.json");

const CENTRASE_LOGO_B64 = "";

function saveGuardClawConfig(privacy: Record<string, unknown>): void {
  try {
    const dir = join(process.env.HOME ?? "/tmp", ".openclaw");
    mkdirSync(dir, { recursive: true });
    let existing: Record<string, unknown> = {};
    try {
      existing = JSON.parse(readFileSync(GUARDCLAW_CONFIG_PATH, "utf-8")) as Record<string, unknown>;
    } catch {
      /* file may not exist yet or is malformed — start from defaults */
    }
    const updated = { ...existing, privacy };
    writeFileSync(GUARDCLAW_CONFIG_PATH, JSON.stringify(updated, null, 2), "utf-8");
  } catch {
    // best-effort persistence
  }
}

export type DashboardDeps = {
  pluginId: string;
  pluginConfig: Record<string, unknown>;
  pipeline: RouterPipeline | null;
};

let deps: DashboardDeps | null = null;

export function initDashboard(d: DashboardDeps): void {
  deps = d;
}

const MAX_SENDER_ID_LENGTH = 128;
const MAX_CORRECTION_MESSAGE_LENGTH = 2000;

/** Trim and validate a sender ID — returns null if empty or too long. */
function parseSenderId(raw: unknown): string | null {
  const s = typeof raw === "string" ? raw.trim() : "";
  if (!s || s.length > MAX_SENDER_ID_LENGTH) return null;
  return s;
}

function readBody(req: IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    const chunks: Buffer[] = [];
    req.on("data", (c: Buffer) => chunks.push(c));
    req.on("end", () => resolve(Buffer.concat(chunks).toString("utf-8")));
    req.on("error", reject);
  });
}

function json(res: ServerResponse, data: unknown, status = 200): void {
  res.writeHead(status, { "Content-Type": "application/json" });
  res.end(JSON.stringify(data));
}

function html(res: ServerResponse, body: string): void {
  res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
  res.end(body);
}

export async function statsHttpHandler(
  req: IncomingMessage,
  res: ServerResponse,
): Promise<boolean> {
  const url = req.url ?? "";
  const parsedUrl = new URL(url, "http://localhost");
  const reqPath = parsedUrl.pathname;
  const base = "/plugins/guardclaw/stats";

  if (!reqPath.startsWith(base)) return false;

  const sub = reqPath.slice(base.length) || "/";

  if (req.method === "GET" && sub === "/") {
    html(res, dashboardHtml());
    return true;
  }

  if (req.method === "GET" && sub === "/api/summary") {
    const collector = getGlobalCollector();
    if (!collector) {
      json(res, { error: "not initialized" }, 503);
      return true;
    }
    json(res, collector.getSummary());
    return true;
  }

  if (req.method === "GET" && sub === "/api/hourly") {
    const collector = getGlobalCollector();
    if (!collector) {
      json(res, { error: "not initialized" }, 503);
      return true;
    }
    json(res, collector.getHourly());
    return true;
  }

  if (req.method === "GET" && sub === "/api/sessions") {
    const collector = getGlobalCollector();
    if (!collector) {
      json(res, { error: "not initialized" }, 503);
      return true;
    }
    json(res, collector.getSessionStats());
    return true;
  }

  if (req.method === "GET" && sub === "/api/synthesis-stats") {
    try {
      const raw = readFileSync(GUARDCLAW_STATS_PATH, "utf-8");
      const stats = JSON.parse(raw) as Record<string, unknown>;
      json(res, (stats.synthesis as Record<string, unknown>) ?? {});
    } catch {
      json(res, {});
    }
    return true;
  }

  if (req.method === "GET" && sub === "/api/current-loop-highest-level") {
    const sessionKey = parsedUrl.searchParams.get("sessionKey") ?? undefined;
    json(res, getCurrentLoopHighestLevel(sessionKey));
    return true;
  }

  if (req.method === "GET" && sub === "/api/last-turn-tokens") {
    const sessionKey = parsedUrl.searchParams.get("sessionKey") ?? undefined;
    const data = getLastTurnTokens(sessionKey);
    if (!data) {
      json(res, { error: "no last-turn router tokens yet" }, 404);
      return true;
    }
    json(res, data);
    return true;
  }

  if (req.method === "GET" && sub === "/api/reply-model-origin") {
    const sessionKey = parsedUrl.searchParams.get("sessionKey") ?? undefined;
    const origin = getLastReplyModelOrigin(sessionKey);
    const loopSummary = getLastReplyLoopSummary(sessionKey);
    if (!origin || !loopSummary) {
      json(res, { error: "no reply-model-origin data yet" }, 404);
      return true;
    }
    json(res, {
      sessionKey: origin.sessionKey,
      timestamp: origin.timestamp,
      provider: origin.provider,
      model: origin.model,
      origin: origin.origin,
      reason: origin.reason,
      loopTotalTokens: loopSummary.loopTotalTokens,
      loopLocalTokens: loopSummary.loopLocalTokens,
      loopCloudTokens: loopSummary.loopCloudTokens,
      routerTokens: loopSummary.routerTokens,
    });
    return true;
  }

  if (req.method === "POST" && sub === "/api/reset") {
    const collector = getGlobalCollector();
    if (!collector) {
      json(res, { error: "not initialized" }, 503);
      return true;
    }
    await collector.reset();
    json(res, { ok: true });
    return true;
  }

  if (req.method === "GET" && sub === "/api/detections") {
    const states = getAllSessionStates();
    const events: Array<{
      sessionKey: string;
      level: string;
      checkpoint: string;
      reason?: string;
      timestamp: number;
    }> = [];
    // S1/S2/S3 from in-memory session state
    states.forEach((state) => {
      for (const d of state.detectionHistory) {
        if (d.level === "S0") continue; // S0 comes from the persistent injection log below
        events.push({
          sessionKey: state.sessionKey,
          level: d.level,
          checkpoint: d.checkpoint,
          reason: d.reason,
          timestamp: d.timestamp,
        });
      }
    });
    // S0 from persistent injection log — survives session end and restarts
    try {
      const raw = readFileSync(GUARDCLAW_INJECTIONS_PATH, "utf-8");
      const injections = JSON.parse(raw) as Array<{
        ts: string; session: string; action: string; score: number;
        patterns: string[]; source: string; preview: string;
      }>;
      for (const entry of injections) {
        events.push({
          sessionKey: entry.session,
          level: "S0",
          checkpoint: "onUserMessage",
          reason: `${entry.action} (score ${entry.score}) [${entry.source}]: ${entry.patterns.join(", ")} — "${entry.preview}"`,
          timestamp: new Date(entry.ts).getTime(),
        });
      }
    } catch { /* file may not exist yet */ }
    events.sort((a, b) => b.timestamp - a.timestamp);
    json(res, events.slice(0, 500));
    return true;
  }

  if (req.method === "GET" && sub === "/api/config") {
    const liveConfig = getLiveConfig();
    const cfgAny = liveConfig as Record<string, unknown>;
    json(res, {
      privacy: {
        enabled: liveConfig.enabled,
        localModel: liveConfig.localModel,
        guardAgent: liveConfig.guardAgent,
        s2Policy: liveConfig.s2Policy,
        proxyPort: liveConfig.proxyPort,
        checkpoints: liveConfig.checkpoints,
        rules: liveConfig.rules,
        localProviders: liveConfig.localProviders,
        modelPricing: liveConfig.modelPricing,
        session: liveConfig.session,
        routers: cfgAny.routers,
        pipeline: cfgAny.pipeline,
        injection: (liveConfig as Record<string,unknown>).injection,
        budget: (liveConfig as Record<string,unknown>).budget,
        modelAdvisor: (liveConfig as Record<string,unknown>).modelAdvisor,
      },
    });
    return true;
  }

  if (req.method === "POST" && sub === "/api/config") {
    if (!deps) {
      json(res, { error: "dashboard not initialized" }, 503);
      return true;
    }
    try {
      const body = JSON.parse(await readBody(req));

      if (body.privacy) {
        updateLiveConfig(body.privacy);

        const existingPrivacy = ((deps.pluginConfig as Record<string, unknown>).privacy ??
          {}) as Record<string, unknown>;
        // Deep-merge routers and pipeline so per-router saves don't clobber siblings
        const incomingRouters = body.privacy.routers as Record<string, unknown> | undefined;
        const incomingPipeline = body.privacy.pipeline as Record<string, unknown> | undefined;
        if (incomingRouters) {
          body.privacy.routers = {
            ...(existingPrivacy.routers as Record<string, unknown> ?? {}),
            ...incomingRouters,
          };
        }
        if (incomingPipeline) {
          body.privacy.pipeline = {
            ...(existingPrivacy.pipeline as Record<string, unknown> ?? {}),
            ...incomingPipeline,
          };
        }
        const mergedPrivacy = { ...existingPrivacy, ...body.privacy } as Record<string, unknown>;

        // Persist to guardclaw.json (does NOT touch openclaw.json → no restart)
        saveGuardClawConfig(mergedPrivacy);

        // Dynamically register/update configurable routers in the pipeline
        if (body.privacy.routers && deps.pipeline) {
          const routers = body.privacy.routers as Record<
            string,
            { type?: string; enabled?: boolean }
          >;
          for (const [id, reg] of Object.entries(routers)) {
            if (reg.type === "configurable" && !deps.pipeline.hasRouter(id)) {
              deps.pipeline.register(
                createConfigurableRouter(id),
                reg as Parameters<typeof deps.pipeline.register>[1],
              );
            }
          }
          // Re-configure pipeline with updated router configs and order
          const mergedPrivacy = { ...existingPrivacy, ...body.privacy } as Record<string, unknown>;
          deps.pipeline.configure({
            routers: mergedPrivacy.routers as Record<
              string,
              Parameters<typeof deps.pipeline.register>[1]
            >,
            pipeline: mergedPrivacy.pipeline as Record<string, string[]>,
          });
          // Update deps.pluginConfig so test-classify picks up new options
          (deps.pluginConfig as Record<string, unknown>).privacy = mergedPrivacy;
        }
      }

      json(res, { ok: true });
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  // ── Corrections API (learning loop) ──

  if (req.method === "GET" && sub === "/api/corrections") {
    json(res, { corrections: getCorrections() });
    return true;
  }

  if (req.method === "POST" && sub === "/api/corrections") {
    try {
      const body = JSON.parse(await readBody(req)) as {
        message: string;
        predicted: string;
        corrected: string;
        reason?: string;
      };
      if (!body.message || !body.predicted || !body.corrected) {
        json(res, { error: "message, predicted, and corrected are required" }, 400);
        return true;
      }
      if (body.message.length > MAX_CORRECTION_MESSAGE_LENGTH) {
        json(res, { error: `message too long (max ${MAX_CORRECTION_MESSAGE_LENGTH} chars)` }, 400);
        return true;
      }
      const validLevels = ["S1", "S2", "S3"];
      if (!validLevels.includes(body.predicted) || !validLevels.includes(body.corrected)) {
        json(res, { error: "predicted and corrected must be S1, S2, or S3" }, 400);
        return true;
      }
      if (body.predicted === body.corrected) {
        json(res, { error: "predicted and corrected must differ" }, 400);
        return true;
      }
      const correction = await addCorrection({
        message: body.message,
        predicted: body.predicted as "S1" | "S2" | "S3",
        corrected: body.corrected as "S1" | "S2" | "S3",
        reason: body.reason,
      });
      json(res, { ok: true, correction });
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  if (req.method === "DELETE" && sub.startsWith("/api/corrections/")) {
    const id = sub.slice("/api/corrections/".length);
    if (!id) {
      json(res, { error: "correction ID required" }, 400);
      return true;
    }
    const deleted = deleteCorrection(id);
    json(res, { ok: deleted, id });
    return true;
  }

  // ── Prompts API ──

  const EDITABLE_PROMPTS: Record<string, { label: string; defaultContent: string }> = {
    "detection-system": {
      label: "Privacy Detection (S1/S2/S3 Classifier)",
      defaultContent: DEFAULT_DETECTION_SYSTEM_PROMPT,
    },
    "token-saver-judge": {
      label: "Token-Saver (Task Complexity Judge)",
      defaultContent: DEFAULT_JUDGE_PROMPT,
    },
    "pii-extraction": {
      label: "PII Extraction Engine",
      defaultContent: DEFAULT_PII_EXTRACTION_PROMPT,
    },
  };

  if (req.method === "GET" && sub === "/api/prompts") {
    const result: Record<
      string,
      { label: string; content: string; isCustom: boolean; defaultContent: string }
    > = {};
    for (const [name, meta] of Object.entries(EDITABLE_PROMPTS)) {
      const fromDisk = readPromptFromDisk(name);
      result[name] = {
        label: meta.label,
        content: fromDisk ?? meta.defaultContent,
        isCustom: fromDisk !== null,
        defaultContent: meta.defaultContent,
      };
    }
    json(res, result);
    return true;
  }

  if (req.method === "POST" && sub === "/api/prompts") {
    try {
      const body = JSON.parse(await readBody(req)) as { name: string; content: string };
      if (!body.name || typeof body.content !== "string") {
        json(res, { error: "name and content required" }, 400);
        return true;
      }
      // Allow both built-in prompts and custom router prompts (custom-*)
      if (!EDITABLE_PROMPTS[body.name] && !body.name.startsWith("custom-")) {
        json(res, { error: `Unknown prompt: ${body.name}` }, 400);
        return true;
      }
      writePrompt(body.name, body.content);
      json(res, { ok: true });
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  // ── Test Classify API ──

  if (req.method === "POST" && sub === "/api/test-classify") {
    if (!deps?.pipeline) {
      json(res, { error: "pipeline not initialized" }, 503);
      return true;
    }
    try {
      const body = JSON.parse(await readBody(req)) as {
        message: string;
        checkpoint?: string;
        router?: string;
      };
      if (!body.message?.trim()) {
        json(res, { error: "message required" }, 400);
        return true;
      }
      const checkpoint = (body.checkpoint ?? "onUserMessage") as
        | "onUserMessage"
        | "onToolCallProposed"
        | "onToolCallExecuted";

      if (body.router) {
        const decision = await deps.pipeline.runSingle(
          body.router,
          { checkpoint, message: body.message, sessionKey: "__test__" },
          deps.pluginConfig,
        );
        if (!decision) {
          json(res, { error: `Router not found: ${body.router}` }, 404);
          return true;
        }
        json(res, {
          level: decision.level,
          action: decision.action,
          target: decision.target,
          reason: decision.reason,
          confidence: decision.confidence,
          routerId: decision.routerId,
        });
      } else {
        // Full pipeline test
        const decision = await deps.pipeline.run(
          checkpoint,
          { checkpoint, message: body.message, sessionKey: "__test__" },
          deps.pluginConfig,
        );
        json(res, {
          level: decision.level,
          action: decision.action,
          target: decision.target,
          reason: decision.reason,
          confidence: decision.confidence,
          routerId: decision.routerId,
        });
      }
    } catch (err) {
      json(res, { error: String(err) }, 500);
    }
    return true;
  }

  // ── Presets API ──

  if (req.method === "GET" && sub === "/api/presets") {
    json(res, listPresets());
    return true;
  }

  if (req.method === "POST" && sub === "/api/presets/apply") {
    try {
      const body = JSON.parse(await readBody(req)) as { id: string; applyDefaultModel?: boolean };
      if (!body.id) {
        json(res, { error: "id required" }, 400);
        return true;
      }
      const result = applyPresetAction(body.id, { applyDefaultModel: body.applyDefaultModel });
      json(res, result, result.ok ? 200 : 404);
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  if (req.method === "POST" && sub === "/api/presets/save") {
    try {
      const body = JSON.parse(await readBody(req)) as { name: string };
      if (!body.name?.trim()) {
        json(res, { error: "name required" }, 400);
        return true;
      }
      json(res, saveCurrentAsPreset(body.name));
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  if (req.method === "DELETE" && sub.startsWith("/api/presets/")) {
    const presetId = decodeURIComponent(sub.slice("/api/presets/".length));
    if (!presetId) {
      json(res, { error: "id required" }, 400);
      return true;
    }
    const result = deletePresetAction(presetId);
    json(res, result, result.ok ? 200 : 400);
    return true;
  }

  if (req.method === "GET" && sub === "/api/banned") {
    // Read from in-memory live config — always reflects the current ban state including
    // senders auto-banned this session before the async file write has completed.
    const banned = getLiveInjectionConfig().banned_senders ?? [];
    json(res, { banned });
    return true;
  }

  if (req.method === "POST" && sub === "/api/unban") {
    try {
      const body = JSON.parse(await readBody(req)) as { senderId: string };
      const senderId = parseSenderId(body.senderId);
      if (!senderId) {
        json(res, { error: "senderId required (max 128 chars)" }, 400);
        return true;
      }
      // Update in-memory live config immediately so the unban takes effect right away
      const newBanned = (getLiveInjectionConfig().banned_senders ?? []).filter((id) => id !== senderId);
      updateLiveInjectionConfig({ banned_senders: newBanned });
      // Persist to guardclaw.json under the correct privacy.injection path
      let cfg: Record<string, unknown> = {};
      try {
        cfg = JSON.parse(readFileSync(GUARDCLAW_CONFIG_PATH, "utf-8")) as Record<string, unknown>;
      } catch { /* file may not exist */ }
      if (!cfg.privacy) cfg.privacy = {};
      const priv = cfg.privacy as Record<string, unknown>;
      if (!priv.injection) priv.injection = {};
      (priv.injection as Record<string, unknown>).banned_senders = newBanned;
      writeFileSync(GUARDCLAW_CONFIG_PATH, JSON.stringify(cfg, null, 2), "utf-8");
      json(res, { ok: true });
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  // ── Exempt Senders API ──

  if (req.method === "GET" && sub === "/api/exempt") {
    const exempt = getLiveInjectionConfig().exempt_senders ?? [];
    json(res, { exempt });
    return true;
  }

  if (req.method === "POST" && sub === "/api/exempt") {
    try {
      const body = JSON.parse(await readBody(req)) as { senderId: string; label?: string };
      const senderId = parseSenderId(body.senderId);
      if (!senderId) {
        json(res, { error: "senderId required (max 128 chars)" }, 400);
        return true;
      }
      const current = getLiveInjectionConfig().exempt_senders ?? [];
      if (current.includes(senderId)) {
        json(res, { ok: true, already: true });
        return true;
      }
      const newExempt = [...current, senderId];
      updateLiveInjectionConfig({ exempt_senders: newExempt });
      let cfg: Record<string, unknown> = {};
      try {
        cfg = JSON.parse(readFileSync(GUARDCLAW_CONFIG_PATH, "utf-8")) as Record<string, unknown>;
      } catch { /* file may not exist */ }
      if (!cfg.privacy) cfg.privacy = {};
      const priv = cfg.privacy as Record<string, unknown>;
      if (!priv.injection) priv.injection = {};
      (priv.injection as Record<string, unknown>).exempt_senders = newExempt;
      writeFileSync(GUARDCLAW_CONFIG_PATH, JSON.stringify(cfg, null, 2), "utf-8");
      json(res, { ok: true });
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  if (req.method === "DELETE" && sub.startsWith("/api/exempt/")) {
    try {
      const senderId = parseSenderId(decodeURIComponent(sub.slice("/api/exempt/".length)));
      if (!senderId) {
        json(res, { error: "senderId required (max 128 chars)" }, 400);
        return true;
      }
      const newExempt = (getLiveInjectionConfig().exempt_senders ?? []).filter((id) => id !== senderId);
      updateLiveInjectionConfig({ exempt_senders: newExempt });
      let cfg: Record<string, unknown> = {};
      try {
        cfg = JSON.parse(readFileSync(GUARDCLAW_CONFIG_PATH, "utf-8")) as Record<string, unknown>;
      } catch { /* file may not exist */ }
      if (!cfg.privacy) cfg.privacy = {};
      const priv = cfg.privacy as Record<string, unknown>;
      if (!priv.injection) priv.injection = {};
      (priv.injection as Record<string, unknown>).exempt_senders = newExempt;
      writeFileSync(GUARDCLAW_CONFIG_PATH, JSON.stringify(cfg, null, 2), "utf-8");
      json(res, { ok: true });
    } catch (err) {
      json(res, { error: String(err) }, 400);
    }
    return true;
  }

  // ── Model Advisor API ──

  if (req.method === "GET" && sub === "/api/suggestions") {
    const statusFilter = parsedUrl.searchParams.get("status") as "pending" | "accepted" | "dismissed" | null;
    const suggestions = getSuggestions(statusFilter ?? undefined);
    json(res, { suggestions, lastCheckedAt: getLastCheckedAt() });
    return true;
  }

  if (req.method === "POST" && sub.startsWith("/api/suggestions/") && sub.endsWith("/accept")) {
    const id = sub.slice("/api/suggestions/".length, -"/accept".length);
    if (!id) { json(res, { error: "id required" }, 400); return true; }
    try {
      const result = await acceptSuggestion(id);
      json(res, result, result.ok ? 200 : 400);
    } catch (err) {
      json(res, { error: String(err) }, 500);
    }
    return true;
  }

  if (req.method === "POST" && sub.startsWith("/api/suggestions/") && sub.endsWith("/dismiss")) {
    const id = sub.slice("/api/suggestions/".length, -"/dismiss".length);
    if (!id) { json(res, { error: "id required" }, 400); return true; }
    dismissSuggestion(id);
    json(res, { ok: true });
    return true;
  }

  if (req.method === "POST" && sub === "/api/advisor/run") {
    // Trigger a check in the background; return immediately
    runAdvisorChecks().catch(() => {});
    json(res, { ok: true, message: "Advisor check triggered" });
    return true;
  }

  // ── Budget API ──

  if (req.method === "GET" && sub === "/api/budget") {
    const cfg = getLiveConfig().budget;
    const snapshot = getBudgetSnapshot();
    json(res, {
      enabled: cfg?.enabled ?? false,
      dailyCap: cfg?.dailyCap ?? null,
      monthlyCap: cfg?.monthlyCap ?? null,
      warnAt: cfg?.warnAt ?? null,
      action: cfg?.action ?? "warn",
      dailyCost: getDailyCost(),
      monthlyCost: getMonthlyCost(),
      raw: snapshot,
    });
    return true;
  }

  if (req.method === "GET" && sub === "/api/models") {
    const liveConfig = getLiveConfig();
    const endpoint = parsedUrl.searchParams.get("endpoint") ?? liveConfig.localModel?.endpoint ?? "http://localhost:11434";
    const type = parsedUrl.searchParams.get("type") ?? liveConfig.localModel?.type ?? "openai-compatible";
    try {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), 5000);
      let models: string[] = [];
      if (type === "ollama-native") {
        const r = await fetch(`${endpoint}/api/tags`, { signal: controller.signal });
        clearTimeout(timer);
        if (r.ok) {
          const data = await r.json() as { models?: Array<{ name: string }> };
          models = (data.models ?? []).map((m) => m.name);
        }
      } else {
        // openai-compatible (includes ollama in compat mode, LM Studio, vLLM, etc.)
        const r = await fetch(`${endpoint}/v1/models`, { signal: controller.signal });
        clearTimeout(timer);
        if (r.ok) {
          const data = await r.json() as { data?: Array<{ id: string }> };
          models = (data.data ?? []).map((m) => m.id);
        }
      }
      json(res, { models });
    } catch {
      json(res, { models: [], error: "Could not reach model endpoint" });
    }
    return true;
  }

  if (req.method === "GET" && sub === "/api/prices/openrouter") {
    try {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), 8000);
      const r = await fetch("https://openrouter.ai/api/v1/models", { signal: controller.signal });
      clearTimeout(timer);
      if (!r.ok) { json(res, { error: `HTTP ${r.status}` }, 502); return true; }
      const data = await r.json() as { data?: Array<{ id: string; pricing?: { prompt?: string; completion?: string } }> };
      const models = (data.data ?? [])
        .filter((m) => m.pricing?.prompt || m.pricing?.completion)
        .map((m) => ({
          id: m.id,
          inputPer1M: m.pricing?.prompt ? parseFloat(m.pricing.prompt) * 1_000_000 : null,
          outputPer1M: m.pricing?.completion ? parseFloat(m.pricing.completion) * 1_000_000 : null,
        }));
      json(res, { models, fetchedAt: new Date().toISOString() });
    } catch {
      json(res, { error: "Could not reach OpenRouter" }, 502);
    }
    return true;
  }

  return false;
}

